<?php
 class SettingsController extends PageController { private array $availableColors = [ '#F5E6C8' => 'Світлофільтр "Пергамент" (Parchment)', '#FFFFF0' => 'Світлофільтр "Слонова кістка" (Ivory)', '#D2B48C' => 'Світлофільтр "Крафт" (Kraft)', '#F5F5DC' => 'Світлофільтр "Бежевий" (Beige)', '#F0E0C0' => 'Світлофільтр "Старий папір" (Old Paper)', ]; public function action_color(): void { $message = ''; $messageType = 'success'; if ($this->request->isPost()) { $color = $this->request->postString('bg_color', '#F5F5DC'); if (array_key_exists($color, $this->availableColors)) { $_SESSION['bg_color'] = $color; $message = 'Фільтр візора оновлено!'; } else { $message = 'Невідомий код фільтра.'; $messageType = 'error'; } } $this->render('settings/color', [ 'colors' => $this->availableColors, 'currentColor' => $_SESSION['bg_color'] ?? '#F5F5DC', 'message' => $message, 'messageType' => $messageType, ], 'Колір фону'); } public function action_greeting(): void { $message = ''; $messageType = 'success'; if ($this->request->isPost()) { $name = trim($this->request->postString('greeting_name')); $gender = $this->request->postString('greeting_gender'); if ($name === '') { $message = "Позивний/Ім'я не може бути порожнім."; $messageType = 'error'; } elseif (!in_array($gender, ['male', 'female'], true)) { $message = 'Оберіть стать для ідентифікації.'; $messageType = 'error'; } else { $cookieOptions = [ 'expires' => time() + 30 * 24 * 3600, 'path' => '/', 'httponly' => true, 'samesite' => 'Lax', ]; setcookie('greeting_name', $name, $cookieOptions); setcookie('greeting_gender', $gender, $cookieOptions); $_COOKIE['greeting_name'] = $name; $_COOKIE['greeting_gender'] = $gender; $message = 'Протокол привітання активовано!'; } } $this->render('settings/greeting', [ 'message' => $message, 'messageType' => $messageType, 'currentName' => $_COOKIE['greeting_name'] ?? '', 'currentGender' => $_COOKIE['greeting_gender'] ?? '', ], 'Привітання'); } } 